sp_widget.client_script:
api.controller = function($location) {
  var c = this;
  c.submitting = false;

  c.form = {
    space_id: $location.search().space_id || '',
    issue_type: '',
    severity: '',
    description: ''
  };

  c.issueTypes = ['Damage', 'Cleanliness', 'Safety', 'Equipment', 'Noise', 'Access', 'Other'];
  c.severities = ['Low', 'Medium', 'High', 'Critical'];

  c.canSubmit = function() {
    return !!(c.form.space_id && c.form.issue_type && c.form.severity && c.form.description);
  };

  c.submitIssue = function() {
    if (!c.canSubmit()) return;
    c.submitting = true;
    c.data.message = '';
    c.server.get({
      action: 'submit',
      space_id: c.form.space_id,
      issue_type: c.form.issue_type,
      severity: c.form.severity,
      description: c.form.description
    }).then(function(r) {
      c.data = r.data;
      c.submitting = false;
      if (r.data.success) {
        c.form = { space_id: '', issue_type: '', severity: '', description: '' };
      }
    });
  };

  c.goBack = function() {
    $location.search('id', 'cs_portal_browse');
    $location.search('space_id', null);
  };
};

sp_widget.css:
.sp-report-issue {
  padding: 20px 0;
  max-width: 600px;
  margin: 0 auto;
}

.sp-report-title {
  color: $text-color;
  font-size: 24px;
  font-weight: 600;
  margin: 0 0 8px 0;
}

.sp-report-subtitle {
  color: $text-secondary;
  margin: 0 0 24px 0;
}

.sp-report-panel {
  border-radius: $border-radius-large;
  border: 1px solid $border-tertiary;
}

.sp-required {
  color: $brand-danger;
}

.sp-form-actions {
  margin-top: 20px;
  display: flex;
  justify-content: flex-end;
  gap: 10px;
}

.sp-alert {
  padding: 14px 16px;
  border-radius: $border-radius-base;
  margin-bottom: 20px;
}

.sp-alert-success {
  background: $state-success-bg;
  color: $brand-success;
}

.sp-alert-danger {
  background: $state-danger-bg;
  color: $brand-danger;
}

.sp-alert-actions {
  margin-top: 12px;
}

sp_widget.script:
(function() {
  data.spaces = [];
  data.message = '';
  data.success = false;
  data.issueNumber = '';

  try {
    if (input && input.action === 'submit') {
      var gr = new GlideRecord('x_2084960_commun_0_issue');
      gr.initialize();
      gr.setValue('space', input.space_id || '');
      gr.setValue('issue_type', input.issue_type || '');
      gr.setValue('severity', input.severity || '');
      gr.setValue('description', input.description || '');
      gr.setValue('reported_by', gs.getUserID());
      gr.setValue('status', 'new');
      var id = gr.insert();
      if (id) {
        var created = new GlideRecord('x_2084960_commun_0_issue');
        created.addQuery('sys_id', id);
        created.setLimit(1);
        created.query();
        if (created.next()) {
          data.issueNumber = created.getValue('number') + '';
        }
        data.success = true;
        data.message = 'Issue reported successfully. We will look into it.';
      } else {
        data.message = 'Failed to submit issue report.';
      }
      return;
    }

    // Load spaces for dropdown
    var spaceGr = new GlideRecord('x_2084960_commun_0_space');
    spaceGr.orderBy('name');
    spaceGr.setLimit(100);
    spaceGr.query();
    while (spaceGr.next()) {
      data.spaces.push({
        sys_id: spaceGr.getUniqueValue(),
        name: spaceGr.getValue('name') + ''
      });
    }
  } catch(e) {
    gs.error('Report Issue widget error: ' + e.message);
    data.message = 'An error occurred.';
  }
})();
